import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type UserId = string & Brand.Brand<"UserId">;
export const UserId = Brand.nominal<UserId>();

interface User { readonly id: UserId; readonly name: string }

declare const lookupUserUnsafe: (id: UserId) => Effect.Effect<User, Error>;

export const loadUser = (raw: string): Effect.Effect<User, Error> =>
  pipe(UserId(raw), lookupUserUnsafe);

// Call site: loadUser(UserId("u_42")) compiles; loadUser("u_42") does NOT.
```

`Brand.nominal` is type-only — there is no runtime check. The call site must pass through the smart constructor so the structural string is promoted to the nominal `UserId` before reaching `lookupUserUnsafe`.

```ts
import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type Email = string & Brand.Brand<"Email">;

export const Email = Brand.refined<Email>(
  (s) => s.includes("@") && s.length <= 254,
  (s) => Brand.error(`Not a valid email: ${s}`),
);

export const parseEmail = (raw: string): Effect.Effect<Email, Brand.Brand.BrandErrors> =>
  pipe(Email.either(raw), (e) => e._tag === "Right" ? Effect.succeed(e.right) : Effect.fail(e.left));
```

`Brand.refined` returns both a total (`Email("x")` — throws on invalid) and partial (`Email.either("x")` — returns `Either<BrandErrors, Email>`) form. The partial form is what you lift into an `Effect`.

```ts
import { Brand, Effect } from "effect";
import { pipe } from "effect";

export type PositiveInt = number & Brand.Brand<"PositiveInt">;

export const PositiveInt = Brand.refined<PositiveInt>(
  (n) => Number.isInteger(n) && n > 0,
  (n) => Brand.error(`Not a positive integer: ${n}`),
);

const sumPositive = (xs: ReadonlyArray<PositiveInt>): PositiveInt =>
  xs.reduce((acc, x) => (acc + x) as PositiveInt, 1 as PositiveInt);

export const parseAndSum = (raw: ReadonlyArray<number>): Effect.Effect<PositiveInt, Brand.Brand.BrandErrors> =>
  pipe(
    Effect.forEach(raw, (n) => {
      const r = PositiveInt.either(n);
      return r._tag === "Right" ? Effect.succeed(r.right) : Effect.fail(r.left);
    }),
    Effect.map(sumPositive),
  );
```

The nominal type `PositiveInt` flows through arithmetic only via the explicit `as PositiveInt` cast inside `sumPositive`, preserving the compile-time guarantee that nothing outside the constructor can mint one.

Branded types attach a phantom tag to a primitive so two structurally identical strings (e.g. `UserId` and `AccountId`) become non-assignable at compile time. `Brand.nominal` is the zero-runtime-cost constructor; `Brand.refined` adds a predicate.

