import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { getSemigroup } from "fp-ts/ReadonlyNonEmptyArray";
import { getApplicativeValidation, apS } from "fp-ts/Either";
import { sequenceS } from "fp-ts/Apply";

type Err = string;
type V<A> = E.Either<RNEA.ReadonlyNonEmptyArray<Err>, A>;

const ok = <A>(a: A): V<A> => E.right(a);
const bad = (msg: Err): V<never> => E.left([msg] as RNEA.ReadonlyNonEmptyArray<Err>);

const vName = (s: string): V<string> => s.trim().length > 0 ? ok(s) : bad("name is required");
const vEmail = (s: string): V<string> => s.includes("@") ? ok(s) : bad("email missing @");
const vAge = (n: number): V<number> => Number.isInteger(n) && n >= 0 ? ok(n) : bad("age must be a non-negative integer");

export interface User { readonly name: string; readonly email: string; readonly age: number }

const appVal = getApplicativeValidation(getSemigroup<Err>());

export const validateUser = (name: string, email: string, age: number): V<User> =>
  sequenceS(appVal)({ name: vName(name), email: vEmail(email), age: vAge(age) });

export const demo: V<User> = pipe(
  validateUser("", "bad", -1),
  E.chain((u) => E.right(u)),
);
```

`sequenceS` runs every field validator; the Validation applicative combines their Lefts via the `ReadonlyNonEmptyArray` semigroup, so all three errors accumulate instead of short-circuiting.

