import { Effect, Option } from "effect";
import { pipe } from "effect";

class FieldError { readonly _tag = "FieldError" as const; constructor(readonly field: string, readonly msg: string) {} }

const vName = (s: string): Effect.Effect<string, FieldError> =>
  s.trim().length > 0 ? Effect.succeed(s) : Effect.fail(new FieldError("name", "required"));
const vEmail = (s: string): Effect.Effect<string, FieldError> =>
  s.includes("@") ? Effect.succeed(s) : Effect.fail(new FieldError("email", "missing @"));
const vAge = (n: number): Effect.Effect<number, FieldError> =>
  Number.isInteger(n) && n >= 0 ? Effect.succeed(n) : Effect.fail(new FieldError("age", "negative"));

export interface User { readonly name: string; readonly email: string; readonly age: number }

export const validate = (name: string, email: string, age: number): Effect.Effect<User, ReadonlyArray<FieldError>> =>
  pipe(
    Effect.all([vName(name), vEmail(email), vAge(age)], { mode: "validate" }),
    Effect.mapError((arr) => arr.flatMap((o) => Option.isSome(o) ? [o.value] : [])),
    Effect.map(([n, e, a]) => ({ name: n, email: e, age: a })),
  );
```

`Effect.all(_, { mode: "validate" })` returns `ReadonlyArray<Option<E>>` on failure — every validator runs to completion, each error appears at the index of its effect, and `Option.isSome` filters the slots that actually failed.

