import { Effect } from "effect";
import { pipe } from "effect";

class ItemError { readonly _tag = "ItemError" as const; constructor(readonly index: number, readonly msg: string) {} }

const validateItem = (idx: number, s: string): Effect.Effect<string, ItemError> =>
  s.trim().length > 0 ? Effect.succeed(s.trim()) : Effect.fail(new ItemError(idx, "empty"));

export const validateAll = (raw: ReadonlyArray<string>): Effect.Effect<ReadonlyArray<string>, ReadonlyArray<ItemError>> =>
  pipe(
    Effect.partition(raw, (s, i) => validateItem(i, s)),
    Effect.flatMap(([errors, values]) =>
      errors.length > 0 ? Effect.fail(errors) : Effect.succeed(values),
    ),
  );
```

`Effect.partition` splits the stream into successes and failures without short-circuiting — every item is evaluated, and the left slot collects every error observed.

